1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life", () => {
5	  it("should return empty grid when given empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single cell (underpopulation, 0 neighbors)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells (underpopulation, each has 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a cell alive that has exactly 2 live neighbors", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
16	    expect(result).toEqual(
17	      expect.arrayContaining([[1, 0]])
18	    );
19	  });
20	  it("should keep a cell alive that has exactly 3 live neighbors", () => {
21	    const result = nextGeneration([[0, 2], [1, 2], [2, 2], [1, 1]]);
22	    expect(result).toEqual(
23	      expect.arrayContaining([[1, 1]])
24	    );
25	  });
26	  it("should kill a cell with 4 live neighbors (overpopulation)", () => {
27	    const result = nextGeneration([[1, 2], [0, 1], [2, 1], [1, 0], [1, 1]]);
28	    expect(result).not.toEqual(expect.arrayContaining([[1, 1]]));
29	  });
30	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
31	    const result = nextGeneration([[0, 1], [1, 1], [0, 0]]);
32	    expect(result).toEqual(
33	      expect.arrayContaining([[1, 0]])
34	    );
35	  });
36	  it("should keep a block pattern unchanged (still life)", () => {
37	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
38	    const result = nextGeneration(block);
39	    expect(result).toHaveLength(4);
40	    expect(result).toEqual(expect.arrayContaining([[0, 0], [1, 0], [0, 1], [1, 1]]));
41	  });
42	  it.todo("should oscillate a blinker pattern (period 2)");
43	});
