1	export type Cell = [number, number];
2	
3	function cellKey(x: number, y: number): string {
4	  return `${x},${y}`;
5	}
6	
7	function parseKey(key: string): Cell {
8	  const [x, y] = key.split(",").map(Number);
9	  return [x, y];
10	}
11	
12	function countNeighbors(cell: Cell, liveCells: Cell[]): number {
13	  return liveCells.filter(
14	    (other) =>
15	      !(other[0] === cell[0] && other[1] === cell[1]) &&
16	      Math.abs(other[0] - cell[0]) <= 1 &&
17	      Math.abs(other[1] - cell[1]) <= 1
18	  ).length;
19	}
20	
21	export function nextGeneration(liveCells: Cell[]): Cell[] {
22	  const survivors = liveCells.filter((cell) => {
23	    const neighborCount = countNeighbors(cell, liveCells);
24	    return neighborCount === 2 || neighborCount === 3;
25	  });
26	
27	  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
28	  const deadCandidateKeys = new Set<string>();
29	
30	  for (const [x, y] of liveCells) {
31	    for (let dx = -1; dx <= 1; dx++) {
32	      for (let dy = -1; dy <= 1; dy++) {
33	        if (dx === 0 && dy === 0) continue;
34	        const key = cellKey(x + dx, y + dy);
35	        if (!liveSet.has(key)) {
36	          deadCandidateKeys.add(key);
37	        }
38	      }
39	    }
40	  }
41	
42	  const newborn: Cell[] = [];
43	  for (const key of deadCandidateKeys) {
44	    const candidate = parseKey(key);
45	    if (countNeighbors(candidate, liveCells) === 3) {
46	      newborn.push(candidate);
47	    }
48	  }
49	
50	  return [...survivors, ...newborn];
51	}
